from google.cloud import storage, firestore, pubsub_v1
import base64
import json
import os
from datetime import datetime

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-events")
TOPIC_PATH = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC) if PROJECT_ID else None

def process_gcs_file(event, context):
    bucket_name = event["bucket"]
    file_name = event["name"]

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_text()

    document = {
        "bucket": bucket_name,
        "name": file_name,
        "size": event.get("size"),
        "content_preview": content[:1000],
        "updated": event.get("updated"),
        "processed_at": datetime.utcnow().isoformat() + "Z",
    }

    firestore_client.collection("processed_files").document(file_name.replace("/", "_")).set(document)

    message = {
        "bucket": bucket_name,
        "name": file_name,
        "processed_at": document["processed_at"],
    }

    if TOPIC_PATH:
        publisher.publish(
            TOPIC_PATH,
            json.dumps(message).encode("utf-8"),
            bucket=bucket_name,
            name=file_name,
        ).result()

    return "OK"